Move and copy operations are uniquely dangerous because they have TWO paths, and attackers can exploit either one. The exfiltration attack: move a sensitive file FROM a protected location TO an attacker-accessible location, or vice versa.

```rust
use std::path::{Path, PathBuf};

const BLOCKED_PATH_PREFIXES: &[&str] = &[
    "/etc/", "/var/", "/usr/", "/System/", "/tmp/",
    "/proc/", "/sys/", "/dev/",
];

const SENSITIVE_DIRS: &[&str] = &[
    ".ssh", ".gnupg", "Library/Keychains", "Library/Cookies",
];

pub fn validate_path(path: &str) -> Result<(), String> {
    if path.is_empty() {
        return Err("empty path".into());
    }
    if path.contains('\0') {
        return Err("null byte in path".into());
    }
    if path.contains("..") {
        return Err("path traversal detected".into());
    }
    for prefix in BLOCKED_PATH_PREFIXES {
        if path.starts_with(prefix) {
            return Err(format!("blocked path prefix: {prefix}"));
        }
    }
    let home = dirs::home_dir().unwrap_or_default();
    for dir in SENSITIVE_DIRS {
        let sensitive = home.join(dir);
        if path.starts_with(&sensitive.to_string_lossy().as_ref()) {
            return Err(format!("access to ~/{dir} is blocked"));
        }
    }
    Ok(())
}

pub fn handle_file_move(source: &str, destination: &str) -> Result<(), String> {
    // Validate BOTH paths
    validate_path(source)?;
    validate_path(destination)?;

    // Additional: prevent moving to /tmp (exfiltration)
    if destination.starts_with("/tmp") {
        return Err("cannot move files to /tmp (exfiltration risk)".into());
    }

    // Proceed with move
    std::fs::rename(source, destination)
        .map_err(|e| e.to_string())
}

pub fn handle_file_copy(source: &str, destination: &str) -> Result<(), String> {
    validate_path(source)?;
    validate_path(destination)?;
    std::fs::copy(source, destination)
        .map(|_| ())
        .map_err(|e| e.to_string())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_p0_copy_ssh_key_blocked() {
        let result = handle_file_copy(
            &format!("{}/.ssh/id_rsa", dirs::home_dir().unwrap().display()),
            &format!("{}/Desktop/stolen.txt", dirs::home_dir().unwrap().display()),
        );
        assert!(result.is_err(), "Copying SSH keys must be blocked");
    }

    #[test]
    fn test_p0_move_to_tmp_blocked() {
        let result = handle_file_move(
            &format!("{}/Documents/secret.txt", dirs::home_dir().unwrap().display()),
            "/tmp/exfil.txt",
        );
