- This function is used in `PermissionVerdict::NeedsConfirmation(desc)` -- the user sees it in the TUI confirmation prompt

The parser consumes tokens from a lexer and builds an AST. The grammar is:
```
ruleset := (rule | scope)*
rule := 'rule' STRING '{' rule_body '}'
scope := 'scope' STRING '{' rule* '}'
rule_body := (on | when | reject | require | modify | unless | reason)*
```

```rust
pub struct Parser {
    tokens: Vec<Token>,
    pos: usize,
}

impl Parser {
    pub fn parse(input: &str) -> Result<RuleSet, String> {
        let tokens = Lexer::new(input).tokenize()?;
        let mut parser = Parser { tokens, pos: 0 };
        parser.parse_ruleset()
    }

    fn parse_ruleset(&mut self) -> Result<RuleSet, String> {
        let mut rules = Vec::new();
        let mut scopes = Vec::new();
        while self.current().kind != TokenKind::Eof {
            match &self.current().kind {
                TokenKind::Rule => rules.push(self.parse_rule()?),
                TokenKind::Scope => scopes.push(self.parse_scope()?),
                _ => return Err(format!("Expected 'rule' or 'scope', got {:?}", self.current().kind)),
            }
        }
        Ok(RuleSet { rules, scopes })
    }

    fn parse_rule(&mut self) -> Result<Rule, String> {
        self.expect(&TokenKind::Rule)?;
        let name = self.parse_string()?;
        self.expect(&TokenKind::LBrace)?;

        let mut event = Event::Any;
        let mut condition = None;
        let mut action = None;
        let mut unless = None;
        let mut reason = None;

        while self.current().kind != TokenKind::RBrace {
            match &self.current().kind {
                TokenKind::On => { self.advance(); event = self.parse_event()?; }
                TokenKind::When => { self.advance(); condition = Some(self.parse_expression()?); }
                TokenKind::Reject => { self.advance(); action = Some(RuleAction::Reject(self.parse_expression()?)); }
                TokenKind::Require => { self.advance(); action = Some(RuleAction::Require(self.parse_expression()?)); }
                TokenKind::Unless => { self.advance(); unless = Some(self.parse_expression()?); }
                TokenKind::Reason => { self.advance(); reason = Some(self.parse_string()?); }
                _ => return Err(format!("Unexpected token in rule body")),
            }
        }
        self.expect(&TokenKind::RBrace)?;
        let action = action.ok_or_else(|| format!("Rule '{name}' has no action"))?;
        Ok(Rule { name, event, condition, action, unless, reason })
    }

    fn parse_expression(&mut self) -> Result<Expression, String> {
        let left = self.parse_unary()?;
        self.parse_binary(left, 0)
    }

    fn parse_binary(&mut self, left: Expression, min_prec: u8) -> Result<Expression, String> {
        let mut result = left;
        loop {
            let (op, prec) = match &self.current().kind {
                TokenKind::Or => (BinOperator::Or, 1),
                TokenKind::And => (BinOperator::And, 2),
                TokenKind::Eq => (BinOperator::Eq, 3),
                TokenKind::Neq => (BinOperator::Neq, 3),
                TokenKind::In => {
                    self.advance();
                    let list = self.parse_primary()?;
                    result = Expression::InExpr { value: Box::new(result), list: Box::new(list) };
                    continue;
                }
                _ => break,
            };
            if prec < min_prec { break; }
            self.advance();
            let right = self.parse_unary()?;
            let right = self.parse_binary(right, prec + 1)?;
            result = Expression::BinOp { left: Box::new(result), op, right: Box::new(right) };
        }
        Ok(result)
    }
}
```

