Guard each API call on the server's declared capabilities:

```swift
public func listTools() async throws -> [MCPTool] {
    guard isConnected else { throw MCPError.notConnected }
    guard serverCapabilities?.supportsTools == true else {
        throw MCPError.capabilityNotSupported("tools")
    }
    let response = try await sendRequest(method: "tools/list")
    let result: MCPToolListResult = try response.decodeResult(as: MCPToolListResult.self)
    return result.tools
}

public func callTool(name: String, arguments: [String: Any] = [:]) async throws -> MCPToolResult {
    guard isConnected else { throw MCPError.notConnected }
    guard serverCapabilities?.supportsTools == true else {
        throw MCPError.capabilityNotSupported("tools")
    }
    let response = try await sendRequest(method: "tools/call", params: [
        "name": AnyCodable(name),
        "arguments": AnyCodable(arguments)
    ])
    return try response.decodeResult(as: MCPToolResult.self)
}
```

This pattern applies to resources and prompts too. The capabilities are discovered during the initialization handshake (`initialize` method) and cached on the client. Benefits: (1) Fast-fail before network round-trip if the server doesn't support a feature. (2) Clear error messages for the agent loop to handle. (3) The guard pattern is uniform across all MCP APIs.

