Coalesce concurrent refreshes so multiple callers waiting on a valid token don't each fire a refresh:
```swift
private var refreshTask: Task<VATokens, Error>?

public func refreshAccessToken() async throws -> VATokens {
    if let existingTask = refreshTask {
        return try await existingTask.value  // Piggyback on in-flight refresh
    }
    let task = Task<VATokens, Error> { /* actual HTTP refresh */ }
    refreshTask = task
    defer { refreshTask = nil }
    return try await task.value
}
```

This pattern ensures: (1) No unnecessary token refreshes. (2) No race conditions on concurrent API calls. (3) The 5-minute buffer gives plenty of time for the refresh round-trip before the old token actually expires.

```rust
impl SkillBuilder {
    pub fn save_skill(skill: &SkillTemplate, skills_dir: &Path) -> Result<()> {
        std::fs::create_dir_all(skills_dir)?;

        // Sanitize: only alphanumeric, hyphen, underscore
        let safe_name = sanitize_skill_name(&skill.name);
        if safe_name.is_empty() {
            anyhow::bail!("Skill name '{}' sanitizes to empty", skill.name);
        }

        let filename = format!("{safe_name}.md");
        let skill_path = skills_dir.join(&filename);

        // Path traversal guard
        let canonical_dir = skills_dir.canonicalize()?;
        let expected = canonical_dir.join(&filename);
        if !expected.starts_with(&canonical_dir) {
            anyhow::bail!("Skill path escape detected");
        }

        let metadata = serde_json::json!({
            "name": skill.name,
            "trigger": skill.trigger,
            "description": skill.description,
            "confidence": skill.confidence,
        });

        let content = format!(
            "<!-- auto-generated-skill: {} -->\n<!-- metadata: {} -->\n\n{}",
            safe_name, metadata, skill.content
        );
        std::fs::write(&skill_path, content)?;
        Ok(())
    }

    pub fn load_auto_skills(skills_dir: &Path) -> Result<Vec<SkillTemplate>> {
        if !skills_dir.exists() { return Ok(vec![]); }
        let canonical_dir = skills_dir.canonicalize()?;
        let mut skills = Vec::new();

        for entry in std::fs::read_dir(skills_dir)? {
            let path = entry?.path();
            if path.extension().and_then(|e| e.to_str()) != Some("md") { continue; }
            // Security: verify file is inside skills_dir
            if let Ok(canonical) = path.canonicalize() {
                if !canonical.starts_with(&canonical_dir) { continue; }
            }
            let raw = std::fs::read_to_string(&path)?;
            if let Some(skill) = parse_skill_file(&raw) {
                skills.push(skill);
            }
        }
        Ok(skills)
    }
}

fn sanitize_skill_name(input: &str) -> String {
    let mut out = String::with_capacity(input.len());
    let mut last_hyphen = false;
    for ch in input.chars() {
        if ch.is_ascii_alphanumeric() || ch == '_' {
            out.push(ch);
            last_hyphen = false;
        } else if !last_hyphen {
            out.push('-');
            last_hyphen = true;
        }
    }
    out.trim_matches('-').to_string()
}
```

The sanitizer converts `../../evil` to `evil` (dots become hyphens, then leading hyphens are trimmed). Combined with the `canonicalize` + `starts_with` check, there's no way for a generated skill name to escape the skills directory.

