Use an orchestrator pattern with a confidence-gated fallback chain:

```swift
@MainActor
class Orchestrator: ObservableObject {
    @Published private(set) var isProcessing = false
    private let fastModel: FastAIEngine
    private let fullModel: any AIEngine

    func processInput(_ input: String, context: [Message]) async throws -> String {
        isProcessing = true
        defer { isProcessing = false }

        // Try fast model first
        let fastResult = await fastModel.classify(input)
        if fastResult.confidence > 0.85 {
            do {
                return try await fastModel.handle(input)
            } catch {
                // Fast model failed - fall through to full model
            }
        }

        // Full model with conversation context
        guard fullModel.isReady else {
            // If fast model gave us anything, use it
            if fastResult.confidence > 0.5 {
                return fastResult.response
            }
            throw AIError.modelNotLoaded
        }

        return try await fullModel.generateResponse(for: input, context: context)
    }
}
```

Key design points:
- 0.85 confidence threshold prevents low-quality fast responses
- Context is passed to the full model but not the fast model (fast model handles self-contained queries)
- Triple fallback: fast model -> full model -> fast model response (if full model not ready)
- `@MainActor` for thread-safe UI state updates

Separate the streaming path. The caller decides which path based on the routing decision:

```swift
func processInputStreaming(_ input: String, context: [Message]) -> AsyncThrowingStream<String, Error> {
    AsyncThrowingStream { continuation in
        Task {
            await MainActor.run { self.isProcessing = true }
            defer { Task { await MainActor.run { self.isProcessing = false } } }

            do {
                guard fullModel.isReady else {
                    throw AIError.modelNotLoaded
                }
                let stream = try await fullModel.generateStreamingResponse(
                    for: input, context: context)
                for await token in stream {
                    continuation.yield(token)
                }
                continuation.finish()
            } catch {
                continuation.finish(throwing: error)
            }
        }
    }
}
```

The caller handles routing:
```swift
if fastModel.isReflexiveTask(input) {
    let result = try await orchestrator.processInput(input, context: messages)
    display(result)
} else {
    let stream = orchestrator.processInputStreaming(input, context: messages)
    for try await token in stream {
        appendToken(token)
    }
}
```

Don't try to unify these into one method. The fast model path is request-response (show complete answer immediately). The streaming path is incremental (show tokens as they arrive). Different UX patterns.

Track file modification times in the store and skip unchanged files:

```rust
pub fn update_file(&mut self, file_path: &Path) -> Result<()> {
    let rel = file_path.strip_prefix(&self.project_root)
        .unwrap_or(file_path).to_string_lossy().to_string();

    if !file_path.exists() {
        self.store.delete_file(&rel)?;  // File was deleted
        return Ok(());
    }

    let mtime = file_mtime(file_path);
    self.index_single_file(file_path, &rel, mtime)?;
    Ok(())
}

fn file_mtime(path: &Path) -> f64 {
    fs::metadata(path)
        .and_then(|m| m.modified())
        .unwrap_or(SystemTime::UNIX_EPOCH)
        .duration_since(SystemTime::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs_f64()
}
