Distinguish by the presence of an `id` field in the JSON-RPC message:

```swift
private func handleReceivedData(_ data: Data) {
    do {
        let response = try JSONDecoder().decode(JSONRPCResponse.self, from: data)

        if let id = response.id {
            // Response to a request we sent
            if let continuation = pendingRequests.removeValue(forKey: id) {
                if let error = response.error {
                    continuation.resume(throwing: error)
                } else {
                    continuation.resume(returning: response)
                }
            } else {
                logger.warning("Response for unknown request ID: \(id)")
            }
        } else {
            // Server-initiated notification (no id)
            handleServerNotification(response)
        }
    } catch {
        logger.error("Failed to decode: \(error)")
    }
}
```

JSON-RPC 2.0 spec: requests have an `id`, responses echo the `id`, notifications have no `id`. The receive loop runs as a Task that iterates over the transport's async stream. When a response arrives, the matching continuation is resumed (resolving the `sendRequest` caller's await). When a notification arrives, it's handled separately -- typically logging, resource change events, or progress updates.

Layer three levels of health checking: simple ping, boolean healthy check, and detailed result:

```swift
public func ping() async throws -> Bool {
    guard transport.isConnected else { throw MCPError.notConnected }
    let response = try await sendRequest(method: "ping")
    return response.isSuccess || response.result != nil
}

public func isHealthy() async -> Bool {
    guard isConnected else { return false }
    do {
        return try await ping()
    } catch {
        return false
    }
}

public func healthCheck(timeout: TimeInterval = 5.0) async -> HealthCheckResult {
    guard transport.isConnected else {
        return HealthCheckResult(isHealthy: false, latencyMs: nil, error: "Not connected")
    }
    let startTime = Date()
    do {
        _ = try await withTimeout(seconds: timeout) { try await self.ping() }
        let latencyMs = Date().timeIntervalSince(startTime) * 1000
        return HealthCheckResult(isHealthy: true, latencyMs: latencyMs, error: nil)
    } catch {
        return HealthCheckResult(isHealthy: false, latencyMs: nil, error: error.localizedDescription)
    }
}
```

The three tiers serve different callers: `ping()` for programmatic checks that want to handle errors, `isHealthy()` for simple boolean guards, and `healthCheck()` for UI display with latency metrics.

Streaming is handled separately from the standard path because RTAI doesn't support streaming - it returns complete responses:

```swift
func processInputStreaming(_ input: String, context: [Message] = []) -> AsyncThrowingStream<String, Error> {
    return AsyncThrowingStream { continuation in
        Task {
            await MainActor.run { self.isProcessing = true }
            defer { Task { await MainActor.run { self.isProcessing = false } } }

            // NOTE: RTAI check is already done by ChatManager before calling this.
            // Skipping duplicate check saves ~1-2s per query.

            do {
                guard self.aiEngine.isReady else {
                    throw SerenaError.aiModelNotLoaded
                }

                await MainActor.run { self.lastProcessingType = .standardLLM }

                let stream = try await self.aiEngine.generateStreamingResponse(
                    for: input, context: context)

                for await token in stream {
                    continuation.yield(token)
                }
                continuation.finish()

            } catch {
                continuation.finish(throwing: error)
            }
        }
    }
}
```

The caller (ChatManager) handles the routing decision:
```swift
// In ChatManager:
if rtaiManager.isRTAITask(input) {
    // Non-streaming RTAI path
    let result = try await orchestrator.processInput(input, context: messages)
    appendMessage(result)
} else {
    // Streaming LLM path
    let stream = orchestrator.processInputStreaming(input, context: messages)
    for try await token in stream {
        appendToken(token)
    }
}
```

The comment about skipping the duplicate RTAI check is important: `processInputStreaming` doesn't re-check RTAI because the caller already did. Without this optimization, every streaming query would pay a ~1-2s RTAI classification overhead for no benefit.

