```rust
impl ToolRegistry {
    /// Returns true if this tool is read-only (safe for concurrent execution).
    pub fn is_read_only(tool_name: &str) -> bool {
        matches!(
            tool_name,
            "file_read" | "grep" | "glob" | "web_fetch"
                | "ask_user" | "memory_read" | "research"
                | "request_permissions"
        )
    }
}
```

In the agent loop, batch read-only calls:
```rust
async fn execute_tool_calls(
    calls: Vec<ToolCall>,
    registry: &ToolRegistry,
    ctx: &ToolContext,
) -> Vec<(String, Result<ToolResult>)> {
    let (reads, writes): (Vec<_>, Vec<_>) = calls
        .into_iter()
        .partition(|tc| ToolRegistry::is_read_only(&tc.name));

    // Run all read-only tools concurrently
    let read_futures: Vec<_> = reads.iter().map(|tc| {
        let id = tc.id.clone();
        async move {
            let result = registry.execute(&tc.name, tc.arguments.clone(), ctx).await;
            (id, result)
        }
    }).collect();
    let mut results = futures::future::join_all(read_futures).await;

    // Run write tools serially
    for tc in writes {
        let result = registry.execute(&tc.name, tc.arguments.clone(), ctx).await;
        results.push((tc.id.clone(), result));
    }

    results
}
```

