Use `tokio::sync::watch` channel. The sender signals cancellation, receivers poll it cheaply.

```rust
use tokio::sync::watch;

#[derive(Debug)]
pub struct CancelToken {
    sender: watch::Sender<bool>,
    receiver: watch::Receiver<bool>,
}

impl CancelToken {
    pub fn new() -> Self {
        let (sender, receiver) = watch::channel(false);
        Self { sender, receiver }
    }

    /// Signal cancellation. Idempotent -- calling twice is safe.
    pub fn cancel(&self) {
        self.sender.send(true).ok(); // .ok() ignores closed channel
    }

    /// Check whether cancellation was requested. Lock-free read.
    pub fn is_cancelled(&self) -> bool {
        *self.receiver.borrow()
    }

    /// Clone the receiver so another task can observe the signal.
    pub fn clone_receiver(&self) -> watch::Receiver<bool> {
        self.receiver.clone()
    }
}

impl Default for CancelToken {
    fn default() -> Self { Self::new() }
}
```

Usage in a long-running tool:
```rust
async fn execute_with_cancel(&self, params: Value, ctx: &ToolContext,
    cancel: &CancelToken, progress: Option<mpsc::Sender<ToolProgress>>,
) -> Result<ToolResult> {
    let mut child = Command::new("sh").arg("-c").arg(&command).spawn()?;
    loop {
        if cancel.is_cancelled() {
            child.kill().await?;
            return Ok(ToolResult::error("Cancelled"));
        }
        // Check if process finished
        match child.try_wait() {
            Ok(Some(status)) => break,
            _ => tokio::time::sleep(Duration::from_millis(50)).await,
        }
    }
}
```

Why `watch` over `AtomicBool`: watch supports `changed().await` for async waiting, not just polling.

Spawn the cancellation on a timer, run the tool, and verify it returns a cancellation error.

```rust
#[cfg(unix)]
#[tokio::test]
async fn test_bash_tool_cancel_mid_execution() {
    use crate::tools::bash::BashTool;

    let tool = BashTool::new();
    let cancel = CancelToken::new();
    let (tx, mut rx) = mpsc::channel(64);
    let ctx = ToolContext {
        cwd: PathBuf::from("/tmp"),
        project_path: PathBuf::from("/tmp"),
    };

    // Spawn cancellation after 100ms
    let cancel_clone_rx = cancel.clone_receiver();
    let cancel_sender = CancelToken {
        sender: cancel.sender.clone(),
        receiver: cancel_clone_rx,
    };
    tokio::spawn(async move {
        tokio::time::sleep(std::time::Duration::from_millis(100)).await;
        cancel_sender.cancel();
    });

    // Execute a long-running command
    let result = tool
        .execute_with_cancel(
            json!({"command": "sleep 10"}),
            &ctx,
            &cancel,
            Some(tx),
        )
        .await
        .unwrap();

    // Should have been cancelled
    assert!(result.is_error);
    assert!(
        result.output.contains("Cancelled"),
        "expected cancel message, got: {}",
        result.output
    );

    // Drain progress channel
    rx.close();
}
