For a parser state machine:
```rust
pub struct StreamingToolCallParser {
    buffer: String,
    inside_tool_call: bool,
    tool_call_buffer: String,
}

impl StreamingToolCallParser {
    pub fn feed(&mut self, chunk: &str) -> Vec<StreamEvent> {
        self.buffer.push_str(chunk);
        let mut events = Vec::new();

        loop {
            if self.inside_tool_call {
                // Look for closing tag
                if let Some(end_pos) = self.buffer.find("</tool_call>") {
                    // Parse and emit ToolCallComplete
                    // Transition: inside -> outside
                    self.inside_tool_call = false;
                } else {
                    break; // Need more data
                }
            } else {
                // Look for opening tag
                if let Some(start_pos) = self.buffer.find("<tool_call>") {
                    // Emit any preceding Text, then ToolCallStart
                    // Transition: outside -> inside
                    self.inside_tool_call = true;
                } else {
                    break;
                }
            }
        }
        events
    }
}
```

The enum approach is better than integer state codes or stringly-typed states because the compiler enforces you handle every variant in `match` expressions.

```rust
pub struct RulesEngine {
    global_rules: Vec<Rule>,
    scoped_rules: Vec<(String, Vec<Rule>)>, // (path_pattern, rules)
}

impl RulesEngine {
    pub fn new() -> Self {
        Self { global_rules: Vec::new(), scoped_rules: Vec::new() }
    }

    pub fn load(&mut self, input: &str) -> Result<usize, String> {
        let ruleset = Parser::parse(input)?;
        let count = ruleset.rules.len()
            + ruleset.scopes.iter().map(|s| s.rules.len()).sum::<usize>();
        self.global_rules.extend(ruleset.rules);
        for scope in ruleset.scopes {
            self.scoped_rules.push((scope.path, scope.rules));
        }
        Ok(count)
    }

    pub fn evaluate(&self, ctx: &EvalContext, project_path: Option<&str>) -> RuleAction {
        let mut applicable: Vec<&Rule> = Vec::new();

        // Global rules apply to all projects
        for rule in &self.global_rules {
            if event_matches(&rule.event, &ctx.event) {
                applicable.push(rule);
            }
        }

        // Scoped rules only apply when project path matches
        if let Some(project) = project_path {
            for (scope_path, rules) in &self.scoped_rules {
                let expanded = scope_path.replace('~',
                    &dirs::home_dir().unwrap_or_default().to_string_lossy());
                if project.starts_with(&expanded) {
                    for rule in rules {
                        if event_matches(&rule.event, &ctx.event) {
                            applicable.push(rule);
                        }
                    }
                }
            }
        }

        // Evaluate each matching rule
        for rule in applicable {
            if let Some(cond) = &rule.condition {
                if !eval_to_bool(cond, ctx) { continue; }
            }
            if let Some(unless) = &rule.unless {
                if eval_to_bool(unless, ctx) { continue; }
            }
            match &rule.action {
                RuleAction::Reject(expr) => {
                    if eval_to_bool(expr, ctx) {
                        return RuleAction::Reject(rule.reason.clone()
                            .unwrap_or(format!("Rule '{}' rejected", rule.name)));
                    }
                }
                RuleAction::Require(expr) => {
                    if !eval_to_bool(expr, ctx) {
                        return RuleAction::Reject(rule.reason.clone()
                            .unwrap_or(format!("Rule '{}' requirement not met", rule.name)));
                    }
                }
                _ => {}
            }
        }

        RuleAction::Allow
    }
}
```

