The test covers three attack vectors:
1. **Null** -- simplest missing-data case
2. **Wrong type** (array instead of object) -- type confusion
3. **Deep nesting** -- stack overflow / DoS via recursive parsing

The assertion is `is_ok()` because the DummyTool ignores params. For real tools, you'd also test that they return `ToolResult::error()` with a helpful message rather than panicking.

```rust
/// Strip subshell wrappers like $(...), `...`, (...) from command start.
fn strip_subshell(cmd: &str) -> &str {
    let trimmed = cmd.trim();
    if let Some(inner) = trimmed.strip_prefix("$(") {
        if let Some(stripped) = inner.strip_suffix(')') {
            return stripped.trim();
        }
    }
    if let Some(inner) = trimmed.strip_prefix('`') {
        if let Some(stripped) = inner.strip_suffix('`') {
            return stripped.trim();
        }
    }
    if let Some(inner) = trimmed.strip_prefix('(') {
        if let Some(stripped) = inner.strip_suffix(')') {
            return stripped.trim();
        }
    }
    trimmed
}

fn classify_single_bash(cmd: &str) -> PermissionTier {
    let trimmed = cmd.trim();
    let inner = strip_subshell(trimmed);

    // Check destructive patterns on the inner command
    for pattern in DESTRUCTIVE_BASH_PATTERNS {
        if inner.starts_with(pattern) || inner.contains(&format!(" {pattern}")) {
            return PermissionTier::Destructive;
        }
    }

    // Check system path access in write commands
    let first_word = inner.split_whitespace().next().unwrap_or("");
    if matches!(first_word, "tee" | "cp" | "mv" | "mkdir" | "touch") {
        for prefix in SYSTEM_PATH_PREFIXES {
            if inner.contains(prefix) {
                return PermissionTier::Destructive;
            }
        }
    }

    // Safe commands
    for safe in SAFE_BASH_COMMANDS {
        if inner == *safe || inner.starts_with(&format!("{safe} ")) {
            return PermissionTier::Safe;
        }
    }

    PermissionTier::Write // default for unknown
}
```

Test:
```rust
assert_eq!(classify("bash", &json!({"command": "$(rm file.txt)"})), PermissionTier::Destructive);
assert_eq!(classify("bash", &json!({"command": "`rm file.txt`"})), PermissionTier::Destructive);
```

The stripping is one level deep by design. Deeply nested subshells like `$($(rm))` are edge cases that the hard_block_check catches via pattern matching on the raw string.

Use Security framework directly with `kSecClassGenericPassword`:

```swift
private func saveToKeychain(key: String, value: String) {
    let data = value.data(using: .utf8)!
    let query: [String: Any] = [
        kSecClass as String: kSecClassGenericPassword,
        kSecAttrAccount as String: key,
        kSecAttrService as String: "com.myapp.auth"
    ]
    SecItemDelete(query as CFDictionary)  // Delete existing first
    var addQuery = query
    addQuery[kSecValueData as String] = data
    SecItemAdd(addQuery as CFDictionary, nil)
}

private func loadFromKeychain(key: String) -> String? {
    let query: [String: Any] = [
        kSecClass as String: kSecClassGenericPassword,
        kSecAttrAccount as String: key,
        kSecAttrService as String: "com.myapp.auth",
        kSecReturnData as String: true,
        kSecMatchLimit as String: kSecMatchLimitOne
    ]
    var result: AnyObject?
    let status = SecItemCopyMatching(query as CFDictionary, &result)
    guard status == errSecSuccess, let data = result as? Data else { return nil }
    return String(data: data, encoding: .utf8)
}
```

