fn execute_with_cancel(&self, params: Value, ctx: &ToolContext,
    cancel: &CancelToken, progress: Option<mpsc::Sender<ToolProgress>>)
    -> Pin<Box<dyn Future<Output = Result<ToolResult>> + Send + '_>> {
    Box::pin(async move {
        let mut child = tokio::process::Command::new("bash")
            .arg("-c").arg(&command).spawn()?;
        let mut rx = cancel.clone_receiver();
        tokio::select! {
            status = child.wait() => {
