When conversations exceed the context limit, use a hybrid approach: keep recent messages unconditionally, and select older messages by relevance score.

```swift
private let maxContextExchanges = 25  // 50 messages

func getContextMessages(for conversation: Conversation) -> [Message] {
    let messages = conversation.messages
    let maxMessages = maxContextExchanges * 2
    if messages.count <= maxMessages { return messages }

    // Always keep the most recent half
    let recentMessages = Array(messages.suffix(maxMessages / 2))

    // Score older messages and pick the best ones
    let remainingSlots = maxMessages - recentMessages.count
    let olderMessages = Array(messages.dropLast(recentMessages.count))
    let scored = scoreMessages(olderMessages)
    let selected = scored.sorted { $0.score > $1.score }.prefix(remainingSlots)

    // Re-sort by timestamp to maintain conversation flow
    return (Array(selected.map(\.message)) + recentMessages)
        .sorted { $0.timestamp < $1.timestamp }
}

func scoreMessage(_ message: Message) -> Double {
    var score = 1.0
    score += min(Double(message.content.count) / 100.0, 3.0)  // Length
    if message.content.contains("?") { score += 2.0 }  // Questions
    // Technical terms boost
    let techTerms = ["func", "class", "struct", "error"]
    score += Double(techTerms.filter { message.content.contains($0) }.count) * 0.5
    return score
}
```

This three-tier approach (always-keep-recent + relevance-scored-old + timestamp-sorted-merge) preserves conversational coherence while maximizing information density within the context window.

```rust
pub fn build_system_prompt(
    project_path: &Path,
    tool_defs: &[ToolDefinition],
    rules_summary: Option<&str>,
    memory_context: Option<&str>,
    templates: Option<&TemplateSet>,
    enabled_templates: &[String],
    ftai_context: Option<&str>,
    plugin_skills: Option<&str>,
