    // 1. Core identity
    parts.push(format!(
        "You are Forge, a FolkTech AI terminal coding assistant.\n\
         Current project: {}\n", project_path.display()
    ));

    // 2. FTAI.md project instructions (high priority - before tools)
    if let Some(ctx) = ftai_context {
        parts.push(format!(
            "# Project Instructions\n\
             The following instructions come from FTAI.md. You MUST follow them.\n\n{ctx}\n"
        ));
    }

    // 3. Tool descriptions
    if !tool_defs.is_empty() {
        parts.push("# Available Tools\n".to_string());
        for tool in tool_defs {
            parts.push(format!("## {}\n{}\nParameters: {}\n",
                tool.name, tool.description,
                serde_json::to_string_pretty(&tool.parameters).unwrap_or_default()
            ));
        }
    }

    // 4. Active rules
    if let Some(rules) = rules_summary {
        parts.push(format!("# Active Rules\n{rules}\n"));
    }

    // 5. Memory context
    if let Some(memory) = memory_context {
        parts.push(format!("# Memory\n{memory}\n"));
    }

    // 6. Formatting guidelines (conditional on enabled list)
    if let Some(tmpl) = templates {
        let active = enabled_templates(tmpl, enabled_templates);
        if !active.is_empty() {
            parts.push("# Formatting Guidelines\n".to_string());
            for (label, content) in active {
                parts.push(format!("## {label}\n{content}\n"));
            }
        }
    }

