    .into_iter()
    .partition(|tc| ToolRegistry::is_read_only(&tc.name));

// Run all read-only tools concurrently
let read_futures: Vec<_> = read_only.iter()
    .map(|tc| registry.execute(&tc.name, tc.params.clone(), &ctx))
    .collect();
let read_results = futures::future::join_all(read_futures).await;

// Run mutating tools serially
for tc in &mutating {
    let result = registry.execute(&tc.name, tc.params.clone(), &ctx).await;
    // handle result
}
```

Why static classification over self-reporting: the registry is the authority on what's safe. A plugin tool that claims to be read-only but runs `rm -rf` would bypass your safety checks. By centralizing it, you also get a single place to audit. Unknown tools default to mutating (safe default).

```rust
use anyhow::Result;
use std::path::Path;

/// Recursively copy a directory, skipping .git.
fn copy_dir_recursive(src: &Path, dst: &Path) -> Result<()> {
    std::fs::create_dir_all(dst)?;
    for entry in std::fs::read_dir(src)? {
        let entry = entry?;
        let src_path = entry.path();
        let dst_path = dst.join(entry.file_name());

        if src_path.is_dir() {
            // Skip .git directory - don't copy repo metadata
            if entry.file_name() == ".git" {
                continue;
            }
            copy_dir_recursive(&src_path, &dst_path)?;
        } else {
            std::fs::copy(&src_path, &dst_path)?;
        }
    }
    Ok(())
}
```

Why skip `.git`:
1. `.git` can be enormous (full repo history) and is never needed at runtime
2. It may contain hooks that execute on certain git operations, which is a security risk in a plugin directory
3. The plugin was cloned with `--depth=1` anyway, but the `.git` directory still contains refs, config, and pack files

The function uses `entry.file_name()` comparison rather than `src_path.ends_with(".git")` because `ends_with` on `Path` matches path components, which is correct here, but `file_name()` is more explicit about comparing the directory name itself.

Note: this doesn't follow symlinks (which is correct for security - a symlink in the source could point outside the source directory). `std::fs::copy` copies the symlink target's content, not the link itself, which is the safe behavior.

Terminal escape sequence injection is a P1 vulnerability. The attack scenario: a compromised or malicious subprocess returns error messages containing ANSI escape codes like `\x1b[31mMALICIOUS\x1b[0m` or worse, sequences that rewrite terminal content, move the cursor, or change terminal settings.

In a TUI application, raw ANSI sequences can:
1. Overwrite displayed content to hide malicious actions
2. Change terminal colors to make warnings invisible
3. Use cursor repositioning to fake UI elements
4. On some terminals, execute arbitrary commands via title-setting sequences

```rust
/// Strip ANSI escape sequences from untrusted text before display.
pub fn strip_ansi(input: &str) -> String {
    let ansi_re = regex::Regex::new(
        r"\x1b\[[0-9;]*[a-zA-Z]|\x1b\][^\x07]*\x07|\x1b[()][AB012]"
    ).unwrap();
    let stripped = ansi_re.replace_all(input, "");

    // Also strip other control characters except newline and tab
    stripped.chars()
        .filter(|c| !c.is_control() || *c == '\n' || *c == '\t')
        .collect()
}

/// Process subprocess error for safe display in TUI.
pub fn safe_error_display(raw_error: &str) -> String {
    let stripped = strip_ansi(raw_error);
    // Truncate long errors
    if stripped.len() > 500 {
        format!("{}... [truncated]", &stripped[..500])
    } else {
        stripped
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_ansi_color_stripped() {
        let input = "\x1b[31mERROR\x1b[0m: file not found";
        let result = strip_ansi(input);
        assert_eq!(result, "ERROR: file not found");
        assert!(!result.contains('\x1b'));
    }

    #[test]
    fn test_cursor_movement_stripped() {
        let input = "\x1b[2J\x1b[HFake clean screen";
        let result = strip_ansi(input);
        assert_eq!(result, "Fake clean screen");
    }

    #[test]
    fn test_title_injection_stripped() {
        let input = "\x1b]0;EVIL TITLE\x07Normal text";
        let result = strip_ansi(input);
        assert_eq!(result, "Normal text");
    }

    #[test]
    fn test_normal_text_preserved() {
        let input = "error: file not found at /path/to/file";
        assert_eq!(strip_ansi(input), input);
    }
}
```

