What's wrong with this async Rust code?

```rust
async fn execute_tools(tools: Vec<String>, registry: &ToolRegistry) {
    for tool in tools {
        let handle = tokio::spawn(async {
            registry.execute(&tool, json!({}), &ctx).await
        });
        handle.await.unwrap();
    }
}
```

Multiple problems:

1. **`registry` borrowed across `.await`** -- `tokio::spawn` requires `'static` futures, but `registry` is a reference. You can't send a reference into a spawned task.
2. **`tool` moved into closure but iterated** -- the `for` loop moves `tool`, which is fine, but `registry` isn't `'static`.
3. **Sequential despite spawning** -- you `await` each handle immediately, defeating the purpose of spawning.
4. **`ctx` not in scope** -- undefined variable.

**Fixed -- truly concurrent:**
```rust
async fn execute_tools(
    tools: Vec<String>,
    registry: Arc<ToolRegistry>,
    ctx: ToolContext,
) {
    let mut handles = Vec::new();
    for tool in tools {
        let reg = registry.clone();
        let ctx = ToolContext {
            cwd: ctx.cwd.clone(),
            project_path: ctx.project_path.clone(),
        };
        handles.push(tokio::spawn(async move {
            reg.execute(&tool, json!({}), &ctx).await
        }));
    }

    for handle in handles {
        match handle.await {
            Ok(Ok(result)) => { /* success */ }
            Ok(Err(e)) => { /* tool error */ }
            Err(e) => { /* join error (panic in task) */ }
        }
    }
}
```

Key fixes:
- `Arc<ToolRegistry>` makes it cheaply cloneable and `'static`
- `clone()` before each spawn gives each task its own `Arc`
- Collect all handles first, then await them all -- true concurrency
- Handle both the `JoinError` (task panic) and the tool `Result`

Use Swift's structured concurrency with `withCheckedThrowingContinuation` for request/response correlation:

```swift
public actor MCPClient {
    private var requestId: Int = 0
    private var pendingRequests: [Int: CheckedContinuation<JSONRPCResponse, Error>] = [:]

    public func sendRequest(method: String, params: [String: AnyCodable]? = nil) async throws -> JSONRPCResponse {
        guard transport.isConnected else { throw MCPError.notConnected }

        requestId += 1
        let id = requestId
        let request = JSONRPCRequest(id: id, method: method, params: params)
        let data = try request.encodeToLine()
        try await transport.send(data)

        return try await withTimeout(seconds: config.requestTimeout) {
            try await withCheckedThrowingContinuation { continuation in
                self.pendingRequests[id] = continuation
            }
        }
    }

    private func handleReceivedData(_ data: Data) {
        let response = try decoder.decode(JSONRPCResponse.self, from: data)
        if let id = response.id,
           let continuation = pendingRequests.removeValue(forKey: id) {
            continuation.resume(returning: response)
        }
    }

    private func withTimeout<T>(seconds: TimeInterval, operation: @escaping () async throws -> T) async throws -> T {
        try await withThrowingTaskGroup(of: T.self) { group in
            group.addTask { try await operation() }
            group.addTask {
                try await Task.sleep(nanoseconds: UInt64(seconds * 1_000_000_000))
                throw MCPError.timeout
            }
            guard let result = try await group.next() else { throw MCPError.timeout }
            group.cancelAll()
            return result
        }
    }
}
```

The actor isolation ensures thread-safe access to `pendingRequests`. The timeout races the actual operation against a sleep task, cancelling the loser.

