You must resume every pending continuation before discarding it, otherwise the awaiting code hangs forever:

```swift
public func disconnect() async throws {
    isInitialized = false
    serverCapabilities = nil

    // Cancel receive loop
    receiveTask?.cancel()
    receiveTask = nil

    // Resume all pending requests with cancellation error
    for (id, continuation) in pendingRequests {
        logger.warning("Cancelling pending request \(id)")
        continuation.resume(throwing: MCPError.cancelled)
    }
    pendingRequests.removeAll()

    try await transport.stop()
}
```

Key points: (1) Cancel the receive task first so no new responses arrive while we're cleaning up. (2) Resume every continuation with an error -- never just drop them. (3) Clear the dictionary after. (4) Stop transport last. Since this is an `actor`, all access is serialized and we don't need additional locking.

Three-layer design: file walker -> chunker -> embedder -> store.

```rust
pub struct CodeIndexer {
    embedder: TextEmbedding,  // fastembed BGE-small-en-v1.5
    store: SearchStore,        // SQLite-backed vector store
    project_root: PathBuf,
}

impl CodeIndexer {
    pub fn index_project(&mut self, root: &Path, progress: impl Fn(IndexProgress)) -> Result<()> {
        let files = collect_files(root)?;  // Respects .gitignore via `ignore` crate

        for (i, file_path) in files.iter().enumerate() {
            let rel = file_path.strip_prefix(root).unwrap_or(file_path).to_string_lossy();

            // Skip unchanged files (mtime check)
            let mtime = file_mtime(file_path);
            if self.store.is_current(&rel, mtime) { continue; }

            let source = fs::read_to_string(file_path)?;
            let chunks = chunk_source(&rel, &source);
            if chunks.is_empty() {
                self.store.upsert_chunks(&rel, &[], mtime)?;
                continue;
            }

            let texts: Vec<&str> = chunks.iter().map(|c| c.content.as_str()).collect();
            let embeddings = self.embedder.embed(texts, None)?;
            self.store.upsert_chunks(&rel, &rows, mtime)?;

            progress(IndexProgress { files_total: files.len(), files_done: i + 1, ... });
        }

        self.store.prune_deleted_files(root)?;  // Clean up removed files
        Ok(())
    }
}
```

