```rust
use std::collections::HashMap;

const MIN_PATTERN_SESSIONS: usize = 3;
const MIN_SKILL_SUCCESS_RATE: f64 = 0.70;
const MIN_SEQUENCE_LEN: usize = 2;

#[derive(Debug, Clone)]
pub struct ToolPattern {
    pub tool_sequence: Vec<String>,
    pub occurrence_count: usize,
    pub avg_success_rate: f64,
    pub common_args: HashMap<String, String>,
}

impl ToolPattern {
    pub fn is_significant(&self) -> bool {
        self.occurrence_count >= MIN_PATTERN_SESSIONS
            && self.avg_success_rate >= MIN_SKILL_SUCCESS_RATE
    }
}

pub struct SkillBuilder;

impl SkillBuilder {
    pub fn detect_patterns(outcomes: &[SessionOutcome]) -> Vec<ToolPattern> {
        let mut pattern_map: HashMap<Vec<String>, PatternAccum> = HashMap::new();

        for outcome in outcomes {
            let tools: Vec<String> = outcome.tool_calls.iter()
                .map(|tc| tc.tool_name.clone()).collect();

            // All contiguous windows of length 2..N
            for len in MIN_SEQUENCE_LEN..=tools.len() {
                for window in tools.windows(len) {
                    let key = window.to_vec();
                    let accum = pattern_map.entry(key).or_default();
                    if !accum.session_ids.contains(&outcome.session_id) {
                        accum.session_ids.push(outcome.session_id.clone());
                        if outcome.success.is_success() {
                            accum.success_count += 1;
                        }
                    }
                }
            }
        }

        pattern_map.into_iter().map(|(seq, accum)| {
            let total = accum.session_ids.len();
            ToolPattern {
                tool_sequence: seq,
                occurrence_count: total,
                avg_success_rate: if total == 0 { 0.0 }
                    else { accum.success_count as f64 / total as f64 },
                common_args: HashMap::new(),
            }
        }).collect()
    }

    pub fn analyze_sessions(outcomes: &[SessionOutcome]) -> Vec<SkillTemplate> {
        Self::detect_patterns(outcomes)
            .iter()
            .filter(|p| p.is_significant())
            .map(|p| Self::pattern_to_skill(p, outcomes))
            .collect()
    }
}
```

The sliding window approach extracts all contiguous sub-sequences of length 2+. If `[file_read, file_edit, bash]` appears in 3+ successful sessions, it becomes a skill template. The template includes:
- A trigger command (`/file_read-file_edit-bash`)
- A workflow description with numbered steps
- Common argument patterns extracted by majority vote on whitespace-split tokens

Skills are saved as markdown files with embedded JSON metadata for round-tripping.

Use `strip_prefix()` and `strip_suffix()` which return `Option<&str>` -- no allocation, no off-by-one errors.

**Wrong way (manual slicing):**
```rust
fn strip_subshell(cmd: &str) -> &str {
    let trimmed = cmd.trim();
    if trimmed.starts_with("$(") && trimmed.ends_with(")") {
        return &trimmed[2..trimmed.len()-1]; // fragile, breaks on multibyte chars
    }
    trimmed
}
```

**Idiomatic:**
```rust
fn strip_subshell(cmd: &str) -> &str {
    let trimmed = cmd.trim();

    // $(...)
    if let Some(inner) = trimmed.strip_prefix("$(") {
        if let Some(stripped) = inner.strip_suffix(')') {
            return stripped.trim();
        }
    }

    // `...`
    if let Some(inner) = trimmed.strip_prefix('`') {
        if let Some(stripped) = inner.strip_suffix('`') {
            return stripped.trim();
        }
    }

    // (...)
    if let Some(inner) = trimmed.strip_prefix('(') {
        if let Some(stripped) = inner.strip_suffix(')') {
            return stripped.trim();
        }
    }

    trimmed
}
```

Advantages:
- Returns `&str` (borrows from input) -- zero allocation
- `strip_prefix` works on `&str` or `char` -- handles both
- No manual index math -- impossible to hit a multibyte char boundary
- Pattern reads top-to-bottom: try `$(...)`, then backticks, then parens

Layer it as: hard block check -> classify tier -> check against permission mode and grant cache.

```rust
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PermissionTier { Safe, Write, Destructive }

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum PermissionVerdict { Approved, NeedsConfirmation(String), Blocked(String) }

pub fn check_permission(
    tier: PermissionTier,
    mode: &PermissionMode,
    grant_cache: &GrantCache,
    tool_name: &str,
    params: &Value,
) -> PermissionVerdict {
    match tier {
        PermissionTier::Safe => PermissionVerdict::Approved,
        PermissionTier::Write => match mode {
            PermissionMode::Ask => {
                if grant_cache.matches(tool_name, params) {
                    PermissionVerdict::Approved
                } else {
                    PermissionVerdict::NeedsConfirmation(describe_action(tool_name, params))
                }
            }
            PermissionMode::Auto | PermissionMode::Yolo => PermissionVerdict::Approved,
        },
        PermissionTier::Destructive => {
            // ALWAYS requires confirmation, regardless of mode.
            // Grant cache never covers destructive actions.
            PermissionVerdict::NeedsConfirmation(describe_action(tool_name, params))
        }
    }
}
```

Three permission modes: Ask (prompt for writes), Auto (auto-approve writes, prompt for destructive), Yolo (auto-approve writes, still prompt for destructive). Destructive always prompts.

The hard block check runs first and returns `Blocked` unconditionally for things like `rm -rf /` or writing to `/etc/passwd`.

Split compound commands on shell operators, classify each segment, take the worst:

```rust
fn classify_bash(params: &Value) -> PermissionTier {
    let command = params.get("command").and_then(|v| v.as_str()).unwrap_or("");
    let segments = split_compound_command(command);
    let mut worst = PermissionTier::Safe;
    for segment in &segments {
        let tier = classify_single_bash(segment);
        worst = worse_tier(worst, tier);
    }
    worst
}
```

`split_compound_command` handles `&&`, `||`, `;`, and `|` while respecting single and double quotes. So `echo "hello && world"` stays as one segment.

Each segment goes through:
1. Strip subshell wrappers: `$(...)`, backticks, `(...)`
2. Check destructive patterns: `rm`, `sudo`, `kill`, `chmod 777`
3. Check system path access in write commands
4. Check safe command list: `ls`, `cat`, `grep`, `cargo test`, etc.
5. Default: Write

For your example: `ls -la && rm -rf /tmp/stuff` -> [`ls -la`, `rm -rf /tmp/stuff`] -> Safe + Destructive -> Destructive. The user gets prompted before execution.

Track `applied_count` and `success_after_apply` for each rule, then check for rules that should be disabled:

```rust
pub fn increment_rule_applied(&self, name: &str) -> Result<()> {
    self.conn.execute(
        "UPDATE generated_rules SET applied_count = applied_count + 1 WHERE name = ?1",
        [name],
    )?;
    Ok(())
}

pub fn increment_rule_success(&self, name: &str) -> Result<()> {
    self.conn.execute(
        "UPDATE generated_rules SET success_after_apply = success_after_apply + 1 WHERE name = ?1",
        [name],
    )?;
    Ok(())
}

pub fn check_auto_disable(&self) -> Result<Vec<String>> {
    let mut stmt = self.conn.prepare(
        "SELECT name FROM generated_rules
         WHERE disabled = 0 AND applied_count >= 3 AND success_after_apply = 0",
    )?;
    let names = stmt.query_map([], |row| row.get(0))?
        .collect::<Result<Vec<String>, _>>()?;
    Ok(names)
}

pub fn disable_rule(&self, name: &str) -> Result<()> {
    self.conn.execute(
        "UPDATE generated_rules SET disabled = 1 WHERE name = ?1", [name],
    )?;
    Ok(())
}
```

The heuristic: if a rule has been applied 3+ times and produced zero successes, it's probably harmful. The `active_rules()` query filters both by confidence (>= 0.7) and disabled status, with a cap of 20 rules to prevent prompt bloat:

```rust
pub fn active_rules(&self) -> Result<Vec<GeneratedRule>> {
    self.conn.prepare(
        "SELECT name, source, confidence, ftai_rule
         FROM generated_rules
         WHERE confidence >= 0.7 AND disabled = 0
         ORDER BY confidence DESC LIMIT 20"
    )?
    // ... map rows ...
}
```

This creates a self-correcting system: rules that help are reinforced, rules that hurt are removed automatically.

